; Recent assessments here are limited to just three records for brevity;
Performance metrics include AUC, precision, recall, and MCC to measure the effectiveness of a model;
The evaluators' names are derived from their IDs matched in the users table;

sql:
SELECT u.username, me.project_id
FROM model_evaluations AS me
JOIN users AS u ON me.evaluator_id = u.user_id;

SELECT me.evaluation_id, me.model_id, me.project_id, me.auc, d.dataset_id, d.dataset_name, d.data_source
FROM model_evaluations AS me
INNER JOIN datasets AS d ON me.dataset_id = d.dataset_id;

SELECT * 
FROM evaluation_logs 
WHERE status = 'success';

